import scala.xml._

class XmlConfigService {

  def parseConfig(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    (xml \\ "Setting").flatMap(setting => {
      val nameOp = setting.attribute("name").map(_.text)
      val valueOp = setting.attribute("value").map(_.text)

      for {
        name <- nameOp
        value <- valueOp
      } yield (name, value)
    }).toMap
  }

  def getSettingValue(xmlString: String, settingName: String): Option[String] = 
    parseConfig(xmlString).get(settingName)
}